/*
* Calculate period 
*
* by Helen Callisaya
*/
var dateVariables = new Object();
var currentDate = Date.now();
var currentYear = moment(currentDate).format('YYYY');
dateVariables['YQP_CURRENT_DATE'] = currentDate;
if (Number(moment(currentDate).format('MM')) < 7) {
	var y = String(Number(currentYear) - 1);
	dateVariables['YQP_INITIAL_DAY'] = '01';
    dateVariables['YQP_INITIAL_MONTH'] = '07';
    dateVariables['YQP_INITIAL_YEAR'] = y;
    dateVariables['YQP_INITIAL_DATE'] =  moment(y + '-07-01').format('YYYY-MM-DD hh:mm:ss');
	dateVariables['YQP_FINISH_DAY'] = '30';
    dateVariables['YQP_FINISH_MONTH'] = '06';
    dateVariables['YQP_FINISH_YEAR'] = currentYear;
    dateVariables['YQP_FINISH_DATE'] =  moment(currentYear + '-06-30').format('YYYY-MM-DD');
	
} else {
	var y = String(Number(currentYear) + 1);
	dateVariables['YQP_INITIAL_DAY'] = '01';
    dateVariables['YQP_INITIAL_MONTH'] = '07';
    dateVariables['YQP_INITIAL_YEAR'] = currentYear;
    dateVariables['YQP_INITIAL_DATE'] =  moment(currentYear + '-07-01').format('YYYY-MM-DD');;
	dateVariables['YQP_FINISH_DAY'] = '30';
    dateVariables['YQP_FINISH_MONTH'] = '06';
    dateVariables['YQP_FINISH_YEAR'] = y;
    dateVariables['YQP_FINISH_DATE'] =  moment(y + '-06-30').format('YYYY-MM-DD');;
}
return dateVariables;

/*
* Actual Month Limit
*
* by Elmer Orihuela
*/
var monthDate = new Object();
var currentDate = Date.now();
var currentYear = moment(currentDate).format('YYYY');
var currentMonth = moment(currentDate).format('MM');
monthDate['YQP_INITIAL_MONTH'] = moment(currentYear + '-' + currentMonth + '-01').format('YYYY-MM-DD');
monthDate['YQP_ACTUAL_DATE'] = moment(currentDate).format('YYYY-MM-DD');
return monthDate;

